// Remove duplicates
const seen = new Set();
const uniqueList = [];
for (const item of chengyuList) {
  if (!seen.has(item.word)) {
    seen.add(item.word);
    uniqueList.push(item);
  }
}

console.log('Total unique entries: ' + uniqueList.length);

// Count by difficulty
const diff1 = uniqueList.filter(e => e.difficulty === 1).length;
const diff2 = uniqueList.filter(e => e.difficulty === 2).length;
const diff3 = uniqueList.filter(e => e.difficulty === 3).length;
console.log('Difficulty 1 (Easy): ' + diff1);
console.log('Difficulty 2 (Medium): ' + diff2);
console.log('Difficulty 3 (Hard): ' + diff3);

// Write file
const output = { chengyuList: uniqueList };
fs.writeFileSync('chengyu-data.json', JSON.stringify(output, null, 2), 'utf8');
